"""Preprocessing: StandardScaler, MinMaxScaler, LabelEncoder, OneHotEncoder,
PolynomialFeatures, RobustScaler, MaxAbsScaler, Normalizer, Binarizer,
FunctionTransformer, KBinsDiscretizer, LabelBinarizer, MultiLabelBinarizer,
OrdinalEncoder, PowerTransformer, QuantileTransformer, SplineTransformer,
TargetEncoder."""
import numpy as np
from sklearn.base import BaseEstimator, TransformerMixin


class StandardScaler(BaseEstimator, TransformerMixin):
    def __init__(self, *, copy=True, with_mean=True, with_std=True):
        self.copy = copy
        self.with_mean = with_mean
        self.with_std = with_std
        self.mean_ = None
        self.scale_ = None

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1: X = X.reshape(-1, 1)
        self.mean_ = np.mean(X, axis=0) if self.with_mean else np.zeros(X.shape[1])
        self.scale_ = np.std(X, axis=0) if self.with_std else np.ones(X.shape[1])
        self.scale_[self.scale_ == 0] = 1.0
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1: X = X.reshape(-1, 1)
        return (X - self.mean_) / self.scale_

    def inverse_transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1: X = X.reshape(-1, 1)
        return X * self.scale_ + self.mean_


class MinMaxScaler(BaseEstimator, TransformerMixin):
    def __init__(self, feature_range=(0, 1), *, copy=True, clip=False):
        self.feature_range = feature_range
        self.copy = copy
        self.clip = clip
        self.min_ = None
        self.scale_ = None
        self.data_min_ = None
        self.data_max_ = None

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1: X = X.reshape(-1, 1)
        self.data_min_ = np.min(X, axis=0)
        self.data_max_ = np.max(X, axis=0)
        rng = self.data_max_ - self.data_min_
        rng[rng == 0] = 1.0
        self.scale_ = (self.feature_range[1] - self.feature_range[0]) / rng
        self.min_ = self.feature_range[0] - self.data_min_ * self.scale_
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1: X = X.reshape(-1, 1)
        return X * self.scale_ + self.min_

    def inverse_transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1: X = X.reshape(-1, 1)
        return (X - self.min_) / self.scale_


class LabelEncoder(BaseEstimator):
    def __init__(self):
        self.classes_ = None

    def fit(self, y):
        self.classes_ = np.unique(y)
        return self

    def transform(self, y):
        y = np.asarray(y)
        mapping = {c: i for i, c in enumerate(self.classes_)}
        return np.array([mapping[v] for v in y])

    def fit_transform(self, y):
        return self.fit(y).transform(y)

    def inverse_transform(self, y):
        return np.array([self.classes_[i] for i in y])


class PolynomialFeatures(BaseEstimator, TransformerMixin):
    def __init__(self, degree=2, *, interaction_only=False, include_bias=True,
                 order='C'):
        self.degree = degree
        self.interaction_only = interaction_only
        self.include_bias = include_bias
        self.order = order

    def fit(self, X, y=None):
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1: X = X.reshape(-1, 1)
        n, p = X.shape
        features = [np.ones((n, 1))] if self.include_bias else []
        for d in range(1, self.degree + 1):
            for j in range(p):
                features.append(X[:, j:j+1] ** d)
        # Cross terms for degree 2
        if self.degree >= 2 and p > 1:
            for i in range(p):
                for j in range(i + 1, p):
                    features.append((X[:, i] * X[:, j]).reshape(-1, 1))
        return np.hstack(features)


class OneHotEncoder(BaseEstimator, TransformerMixin):
    def __init__(self, *, categories='auto', drop=None, sparse_output=False,
                 dtype=None, handle_unknown='error', min_frequency=None,
                 max_categories=None, feature_name_combiner='concat',
                 sparse=False):
        self.categories = categories
        self.drop = drop
        self.sparse_output = sparse_output
        self.dtype = dtype
        self.handle_unknown = handle_unknown
        self.min_frequency = min_frequency
        self.max_categories = max_categories
        self.feature_name_combiner = feature_name_combiner
        self.sparse = sparse  # always dense in this implementation
        self.categories_ = None

    def fit(self, X, y=None):
        X = np.asarray(X)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        self.categories_ = []
        for col in range(X.shape[1]):
            self.categories_.append(np.unique(X[:, col]))
        return self

    def transform(self, X):
        X = np.asarray(X)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n_samples = X.shape[0]
        encoded_cols = []
        for col in range(X.shape[1]):
            cats = self.categories_[col]
            col_encoded = np.zeros((n_samples, len(cats)), dtype=float)
            for i, cat in enumerate(cats):
                col_encoded[:, i] = (X[:, col] == cat).astype(float)
            if self.handle_unknown == 'ignore':
                pass  # unknown categories get all zeros
            encoded_cols.append(col_encoded)
        return np.hstack(encoded_cols)

    def inverse_transform(self, X):
        X = np.asarray(X, dtype=float)
        n_samples = X.shape[0]
        n_features = len(self.categories_)
        result = np.empty((n_samples, n_features), dtype=object)
        col_offset = 0
        for feat_idx in range(n_features):
            n_cats = len(self.categories_[feat_idx])
            sub = X[:, col_offset:col_offset + n_cats]
            indices = np.argmax(sub, axis=1)
            result[:, feat_idx] = self.categories_[feat_idx][indices]
            col_offset += n_cats
        return result


class RobustScaler(BaseEstimator, TransformerMixin):
    def __init__(self, *, with_centering=True, with_scaling=True,
                 quantile_range=(25.0, 75.0), copy=True, unit_variance=False):
        self.with_centering = with_centering
        self.with_scaling = with_scaling
        self.quantile_range = quantile_range
        self.copy = copy
        self.unit_variance = unit_variance
        self.center_ = None
        self.scale_ = None

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        if self.with_centering:
            self.center_ = np.median(X, axis=0)
        else:
            self.center_ = np.zeros(X.shape[1])
        if self.with_scaling:
            q_low, q_high = self.quantile_range
            low = np.percentile(X, q_low, axis=0)
            high = np.percentile(X, q_high, axis=0)
            self.scale_ = high - low
            self.scale_[self.scale_ == 0] = 1.0
        else:
            self.scale_ = np.ones(X.shape[1])
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        return (X - self.center_) / self.scale_

    def inverse_transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        return X * self.scale_ + self.center_


# ---------------------------------------------------------------------------
# MaxAbsScaler
# ---------------------------------------------------------------------------

class MaxAbsScaler(BaseEstimator, TransformerMixin):
    """Scale each feature by its maximum absolute value."""

    def __init__(self, *, copy=True):
        self.copy = copy
        self.max_abs_ = None
        self.scale_ = None

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        self.max_abs_ = np.abs(X).max(axis=0)
        self.scale_ = self.max_abs_.copy()
        self.scale_[self.scale_ == 0] = 1.0
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        return X / self.scale_

    def inverse_transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        return X * self.scale_


# ---------------------------------------------------------------------------
# Normalizer
# ---------------------------------------------------------------------------

class Normalizer(BaseEstimator, TransformerMixin):
    """Row-wise normalization (L1, L2, or max)."""

    def __init__(self, norm='l2', *, copy=True):
        self.norm = norm
        self.copy = copy

    def fit(self, X, y=None):
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(1, -1)
        if self.norm == 'l1':
            norms = np.abs(X).sum(axis=1, keepdims=True)
        elif self.norm == 'l2':
            norms = np.sqrt((X ** 2).sum(axis=1, keepdims=True))
        elif self.norm == 'max':
            norms = np.abs(X).max(axis=1, keepdims=True)
        else:
            raise ValueError(f"Unsupported norm: {self.norm}")
        norms[norms == 0] = 1.0
        return X / norms


# ---------------------------------------------------------------------------
# Binarizer
# ---------------------------------------------------------------------------

class Binarizer(BaseEstimator, TransformerMixin):
    """Threshold values to 0/1."""

    def __init__(self, *, threshold=0.0, copy=True):
        self.threshold = threshold
        self.copy = copy

    def fit(self, X, y=None):
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        return (X > self.threshold).astype(float)


# ---------------------------------------------------------------------------
# FunctionTransformer
# ---------------------------------------------------------------------------

class FunctionTransformer(BaseEstimator, TransformerMixin):
    """Apply a user-supplied function element-wise."""

    def __init__(self, func=None, inverse_func=None, *, validate=False,
                 accept_sparse=False, check_inverse=True,
                 feature_names_out=None, kw_args=None, inv_kw_args=None):
        self.func = func
        self.inverse_func = inverse_func
        self.validate = validate
        self.accept_sparse = accept_sparse
        self.check_inverse = check_inverse
        self.feature_names_out = feature_names_out
        self.kw_args = kw_args
        self.inv_kw_args = inv_kw_args

    def fit(self, X, y=None):
        return self

    def transform(self, X):
        if self.validate:
            X = np.asarray(X, dtype=float)
        if self.func is None:
            return X
        kw = self.kw_args or {}
        return self.func(X, **kw)

    def inverse_transform(self, X):
        if self.inverse_func is None:
            return X
        kw = self.inv_kw_args or {}
        return self.inverse_func(X, **kw)


# ---------------------------------------------------------------------------
# KBinsDiscretizer
# ---------------------------------------------------------------------------

class KBinsDiscretizer(BaseEstimator, TransformerMixin):
    """Bin continuous features into k discrete intervals."""

    def __init__(self, n_bins=5, *, encode='onehot', strategy='quantile',
                 dtype=None, subsample='warn', random_state=None):
        self.n_bins = n_bins
        self.encode = encode
        self.strategy = strategy
        self.dtype = dtype
        self.subsample = subsample
        self.random_state = random_state
        self.bin_edges_ = None
        self.n_bins_ = None

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n_features = X.shape[1]
        self.bin_edges_ = []
        self.n_bins_ = np.empty(n_features, dtype=int)
        for col in range(n_features):
            col_data = X[:, col]
            if self.strategy == 'uniform':
                edges = np.linspace(col_data.min(), col_data.max(), self.n_bins + 1)
            elif self.strategy == 'quantile':
                quantiles = np.linspace(0, 100, self.n_bins + 1)
                edges = np.percentile(col_data, quantiles)
                edges = np.unique(edges)
            elif self.strategy == 'kmeans':
                from sklearn.cluster import KMeans as _KM
                km = _KM(n_clusters=self.n_bins, n_init=1, random_state=self.random_state)
                km.fit(col_data.reshape(-1, 1))
                centers = np.sort(km.cluster_centers_.ravel())
                edges = np.concatenate([[col_data.min()],
                                        (centers[:-1] + centers[1:]) / 2,
                                        [col_data.max()]])
            else:
                edges = np.linspace(col_data.min(), col_data.max(), self.n_bins + 1)
            self.bin_edges_.append(edges)
            self.n_bins_[col] = len(edges) - 1
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n_samples, n_features = X.shape
        if self.encode == 'ordinal':
            result = np.zeros((n_samples, n_features))
            for col in range(n_features):
                result[:, col] = np.clip(
                    np.searchsorted(self.bin_edges_[col][1:-1], X[:, col], side='right'),
                    0, self.n_bins_[col] - 1)
            return result
        # onehot or onehot-dense
        parts = []
        for col in range(n_features):
            bins = np.clip(
                np.searchsorted(self.bin_edges_[col][1:-1], X[:, col], side='right'),
                0, self.n_bins_[col] - 1).astype(int)
            oh = np.zeros((n_samples, self.n_bins_[col]))
            oh[np.arange(n_samples), bins] = 1.0
            parts.append(oh)
        return np.hstack(parts)

    def inverse_transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        if self.encode == 'ordinal':
            result = np.zeros_like(X)
            for col in range(X.shape[1]):
                edges = self.bin_edges_[col]
                bin_idx = X[:, col].astype(int)
                bin_idx = np.clip(bin_idx, 0, len(edges) - 2)
                result[:, col] = (edges[bin_idx] + edges[bin_idx + 1]) / 2
            return result
        # onehot: reconstruct from indicator columns
        parts = []
        offset = 0
        for col in range(len(self.bin_edges_)):
            nb = self.n_bins_[col]
            sub = X[:, offset:offset + nb]
            bin_idx = np.argmax(sub, axis=1)
            edges = self.bin_edges_[col]
            parts.append(((edges[bin_idx] + edges[bin_idx + 1]) / 2).reshape(-1, 1))
            offset += nb
        return np.hstack(parts)


# ---------------------------------------------------------------------------
# LabelBinarizer
# ---------------------------------------------------------------------------

class LabelBinarizer(BaseEstimator, TransformerMixin):
    """One-hot encode a single label column."""

    def __init__(self, *, neg_label=0, pos_label=1, sparse_output=False):
        self.neg_label = neg_label
        self.pos_label = pos_label
        self.sparse_output = sparse_output
        self.classes_ = None

    def fit(self, y):
        y = np.asarray(y)
        self.classes_ = np.unique(y)
        return self

    def transform(self, y):
        y = np.asarray(y)
        n = len(y)
        nc = len(self.classes_)
        if nc == 2:
            result = np.full((n, 1), self.neg_label, dtype=float)
            result[y == self.classes_[1], 0] = self.pos_label
            return result
        result = np.full((n, nc), self.neg_label, dtype=float)
        class_to_idx = {c: i for i, c in enumerate(self.classes_)}
        for i, val in enumerate(y):
            if val in class_to_idx:
                result[i, class_to_idx[val]] = self.pos_label
        return result

    def fit_transform(self, y):
        return self.fit(y).transform(y)

    def inverse_transform(self, Y):
        Y = np.asarray(Y, dtype=float)
        if Y.ndim == 1:
            Y = Y.reshape(-1, 1)
        if len(self.classes_) == 2 and Y.shape[1] == 1:
            return np.where(Y[:, 0] >= (self.pos_label + self.neg_label) / 2,
                            self.classes_[1], self.classes_[0])
        return self.classes_[np.argmax(Y, axis=1)]


# ---------------------------------------------------------------------------
# MultiLabelBinarizer
# ---------------------------------------------------------------------------

class MultiLabelBinarizer(BaseEstimator, TransformerMixin):
    """Multi-label binarizer for sequences of label sets."""

    def __init__(self, *, classes=None, sparse_output=False):
        self.classes = classes
        self.sparse_output = sparse_output
        self.classes_ = None

    def fit(self, y):
        if self.classes is not None:
            self.classes_ = np.asarray(self.classes)
        else:
            all_labels = set()
            for row in y:
                all_labels.update(row)
            self.classes_ = np.array(sorted(all_labels))
        return self

    def transform(self, y):
        nc = len(self.classes_)
        class_to_idx = {c: i for i, c in enumerate(self.classes_)}
        n = len(y)
        result = np.zeros((n, nc), dtype=float)
        for i, row in enumerate(y):
            for label in row:
                if label in class_to_idx:
                    result[i, class_to_idx[label]] = 1.0
        return result

    def fit_transform(self, y):
        return self.fit(y).transform(y)

    def inverse_transform(self, Y):
        Y = np.asarray(Y, dtype=float)
        result = []
        for row in Y:
            result.append(tuple(self.classes_[np.where(row > 0.5)[0]]))
        return result


# ---------------------------------------------------------------------------
# OrdinalEncoder
# ---------------------------------------------------------------------------

class OrdinalEncoder(BaseEstimator, TransformerMixin):
    """Integer-encode categorical features."""

    def __init__(self, *, categories='auto', dtype=np.float64,
                 handle_unknown='error', unknown_value=None,
                 encoded_missing_value=np.nan, min_frequency=None,
                 max_categories=None):
        self.categories = categories
        self.dtype = dtype
        self.handle_unknown = handle_unknown
        self.unknown_value = unknown_value
        self.encoded_missing_value = encoded_missing_value
        self.min_frequency = min_frequency
        self.max_categories = max_categories
        self.categories_ = None

    def fit(self, X, y=None):
        X = np.asarray(X)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        self.categories_ = []
        for col in range(X.shape[1]):
            self.categories_.append(np.unique(X[:, col]))
        return self

    def transform(self, X):
        X = np.asarray(X)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n_samples, n_features = X.shape
        result = np.zeros((n_samples, n_features), dtype=self.dtype)
        for col in range(n_features):
            mapping = {c: i for i, c in enumerate(self.categories_[col])}
            for i in range(n_samples):
                val = X[i, col]
                if val in mapping:
                    result[i, col] = mapping[val]
                elif self.handle_unknown == 'use_encoded_value':
                    result[i, col] = self.unknown_value if self.unknown_value is not None else -1
                else:
                    result[i, col] = -1
        return result

    def inverse_transform(self, X):
        X = np.asarray(X)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n_samples, n_features = X.shape
        result = np.empty((n_samples, n_features), dtype=object)
        for col in range(n_features):
            cats = self.categories_[col]
            for i in range(n_samples):
                idx = int(X[i, col])
                if 0 <= idx < len(cats):
                    result[i, col] = cats[idx]
                else:
                    result[i, col] = None
        return result


# ---------------------------------------------------------------------------
# PowerTransformer
# ---------------------------------------------------------------------------

class PowerTransformer(BaseEstimator, TransformerMixin):
    """Yeo-Johnson power transform to make data more Gaussian."""

    def __init__(self, method='yeo-johnson', *, standardize=True, copy=True):
        self.method = method
        self.standardize = standardize
        self.copy = copy
        self.lambdas_ = None
        self._scaler = None

    @staticmethod
    def _yeo_johnson(x, lam):
        out = np.zeros_like(x, dtype=float)
        pos = x >= 0
        neg = ~pos
        if np.abs(lam) > 1e-10:
            out[pos] = ((x[pos] + 1) ** lam - 1) / lam
        else:
            out[pos] = np.log1p(x[pos])
        if np.abs(lam - 2) > 1e-10:
            out[neg] = -((-x[neg] + 1) ** (2 - lam) - 1) / (2 - lam)
        else:
            out[neg] = -np.log1p(-x[neg])
        return out

    @staticmethod
    def _yeo_johnson_neg_llf(lam, x):
        """Negative log-likelihood for Yeo-Johnson transform."""
        xt = PowerTransformer._yeo_johnson(x, lam)
        n = len(x)
        var = np.var(xt)
        if var < 1e-20:
            return 1e10
        llf = -n / 2.0 * np.log(var)
        llf += (lam - 1) * np.sum(np.sign(x) * np.log1p(np.abs(x)))
        return -llf

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n_features = X.shape[1]
        self.lambdas_ = np.zeros(n_features)
        for col in range(n_features):
            col_data = X[:, col]
            # Grid search for optimal lambda
            best_lam = 1.0
            best_llf = np.inf
            for lam in np.linspace(-2, 2, 41):
                llf = self._yeo_johnson_neg_llf(lam, col_data)
                if llf < best_llf:
                    best_llf = llf
                    best_lam = lam
            self.lambdas_[col] = best_lam
        if self.standardize:
            transformed = self._transform_raw(X)
            self._scaler = StandardScaler()
            self._scaler.fit(transformed)
        return self

    def _transform_raw(self, X):
        result = np.zeros_like(X, dtype=float)
        for col in range(X.shape[1]):
            result[:, col] = self._yeo_johnson(X[:, col], self.lambdas_[col])
        return result

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        result = self._transform_raw(X)
        if self.standardize and self._scaler is not None:
            result = self._scaler.transform(result)
        return result

    def inverse_transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        if self.standardize and self._scaler is not None:
            X = self._scaler.inverse_transform(X)
        result = np.zeros_like(X, dtype=float)
        for col in range(X.shape[1]):
            lam = self.lambdas_[col]
            xt = X[:, col]
            out = np.zeros_like(xt)
            pos = xt >= 0
            neg = ~pos
            if np.abs(lam) > 1e-10:
                out[pos] = (xt[pos] * lam + 1) ** (1.0 / lam) - 1
            else:
                out[pos] = np.expm1(xt[pos])
            if np.abs(lam - 2) > 1e-10:
                out[neg] = 1 - (-(2 - lam) * xt[neg] + 1) ** (1.0 / (2 - lam))
            else:
                out[neg] = -np.expm1(-xt[neg])
            result[:, col] = out
        return result


# ---------------------------------------------------------------------------
# QuantileTransformer
# ---------------------------------------------------------------------------

class QuantileTransformer(BaseEstimator, TransformerMixin):
    """Map features to a uniform or normal distribution via quantiles."""

    def __init__(self, *, n_quantiles=1000, output_distribution='uniform',
                 ignore_implicit_zeros=False, subsample=100000,
                 random_state=None, copy=True):
        self.n_quantiles = n_quantiles
        self.output_distribution = output_distribution
        self.ignore_implicit_zeros = ignore_implicit_zeros
        self.subsample = subsample
        self.random_state = random_state
        self.copy = copy
        self.quantiles_ = None
        self.references_ = None

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        rng = np.random.RandomState(self.random_state)
        n_samples = X.shape[0]
        if n_samples > self.subsample:
            idx = rng.choice(n_samples, self.subsample, replace=False)
            X = X[idx]
        n_q = min(self.n_quantiles, X.shape[0])
        self.references_ = np.linspace(0, 1, n_q)
        percentiles = self.references_ * 100
        self.quantiles_ = np.percentile(X, percentiles, axis=0)
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        result = np.zeros_like(X)
        for col in range(X.shape[1]):
            col_quantiles = self.quantiles_[:, col]
            # Map to [0, 1] via interpolation
            result[:, col] = np.interp(X[:, col], col_quantiles, self.references_)
        if self.output_distribution == 'normal':
            # Clip to avoid inf from ppf at 0 and 1
            result = np.clip(result, 1e-7, 1 - 1e-7)
            # Inverse normal CDF (probit) via rational approximation
            result = self._ppf_normal(result)
        return result

    @staticmethod
    def _ppf_normal(p):
        """Approximate inverse normal CDF (probit function)."""
        # Rational approximation (Beasley-Springer-Moro)
        a = np.zeros_like(p)
        mask_low = p < 0.5
        mask_high = ~mask_low
        # For p < 0.5
        t = np.sqrt(-2.0 * np.log(np.clip(p[mask_low], 1e-15, None)))
        c0, c1, c2 = 2.515517, 0.802853, 0.010328
        d1, d2, d3 = 1.432788, 0.189269, 0.001308
        a[mask_low] = -(t - (c0 + c1 * t + c2 * t ** 2) /
                         (1 + d1 * t + d2 * t ** 2 + d3 * t ** 3))
        # For p >= 0.5
        t = np.sqrt(-2.0 * np.log(np.clip(1 - p[mask_high], 1e-15, None)))
        a[mask_high] = t - (c0 + c1 * t + c2 * t ** 2) / \
                        (1 + d1 * t + d2 * t ** 2 + d3 * t ** 3)
        return a

    def inverse_transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        if self.output_distribution == 'normal':
            # CDF of standard normal via error function approximation
            X = 0.5 * (1 + np.vectorize(self._erf)(X / np.sqrt(2)))
        result = np.zeros_like(X)
        for col in range(X.shape[1]):
            col_quantiles = self.quantiles_[:, col]
            result[:, col] = np.interp(X[:, col], self.references_, col_quantiles)
        return result

    @staticmethod
    def _erf(x):
        """Approximation of the error function."""
        sign = np.sign(x)
        x = np.abs(x)
        t = 1.0 / (1.0 + 0.3275911 * x)
        y = 1.0 - (((((1.061405429 * t - 1.453152027) * t) + 1.421413741) *
                     t - 0.284496736) * t + 0.254829592) * t * np.exp(-x * x)
        return sign * y


# ---------------------------------------------------------------------------
# SplineTransformer
# ---------------------------------------------------------------------------

class SplineTransformer(BaseEstimator, TransformerMixin):
    """Generate B-spline basis features."""

    def __init__(self, n_knots=5, degree=3, *, knots='uniform',
                 extrapolation='constant', include_bias=True, order='C',
                 sparse_output=False):
        self.n_knots = n_knots
        self.degree = degree
        self.knots = knots
        self.extrapolation = extrapolation
        self.include_bias = include_bias
        self.order = order
        self.sparse_output = sparse_output
        self.knots_ = None
        self.n_features_out_ = None

    def _bspline_basis(self, x, knots, degree):
        """Evaluate B-spline basis using Cox-de Boor recursion."""
        n_basis = len(knots) - degree - 1
        n_pts = len(x)
        B = np.zeros((n_pts, n_basis))
        # Degree 0
        for i in range(n_basis + degree):
            if i < len(knots) - 1:
                mask = (x >= knots[i]) & (x < knots[i + 1])
                if i < n_basis + degree:
                    pass  # will be used in recursion
        # Build recursively
        # Start with degree 0 basis
        d0_basis = np.zeros((n_pts, len(knots) - 1))
        for i in range(len(knots) - 1):
            d0_basis[:, i] = ((x >= knots[i]) & (x < knots[i + 1])).astype(float)
        # Handle right boundary
        d0_basis[-1 if n_pts > 0 else 0:, -1] = np.where(
            x[-1:] == knots[-1], 1.0, d0_basis[-1:, -1])
        current = d0_basis
        for d in range(1, degree + 1):
            n_b = current.shape[1] - 1
            new_basis = np.zeros((n_pts, n_b))
            for i in range(n_b):
                denom1 = knots[i + d] - knots[i]
                denom2 = knots[i + d + 1] - knots[i + 1]
                term1 = 0.0
                term2 = 0.0
                if denom1 > 0:
                    term1 = (x - knots[i]) / denom1 * current[:, i]
                if denom2 > 0:
                    term2 = (knots[i + d + 1] - x) / denom2 * current[:, i + 1]
                new_basis[:, i] = term1 + term2
            current = new_basis
        B = current
        return B

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n_features = X.shape[1]
        self.knots_ = []
        total_out = 0
        for col in range(n_features):
            col_data = X[:, col]
            if self.knots == 'uniform':
                internal = np.linspace(col_data.min(), col_data.max(), self.n_knots)
            elif self.knots == 'quantile':
                quantiles = np.linspace(0, 100, self.n_knots)
                internal = np.percentile(col_data, quantiles)
            else:
                internal = np.linspace(col_data.min(), col_data.max(), self.n_knots)
            # Add boundary knots for B-spline
            dt = internal[-1] - internal[0]
            pad = dt * 0.01 if dt > 0 else 1.0
            augmented = np.concatenate([
                np.full(self.degree, internal[0] - pad),
                internal,
                np.full(self.degree, internal[-1] + pad)
            ])
            self.knots_.append(augmented)
            n_basis = len(augmented) - self.degree - 1
            if not self.include_bias:
                n_basis = max(n_basis - 1, 1)
            total_out += n_basis
        self.n_features_out_ = total_out
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        parts = []
        for col in range(X.shape[1]):
            basis = self._bspline_basis(X[:, col], self.knots_[col], self.degree)
            if not self.include_bias and basis.shape[1] > 1:
                basis = basis[:, 1:]
            if self.extrapolation == 'constant':
                xmin = self.knots_[col][self.degree]
                xmax = self.knots_[col][-self.degree - 1]
                below = X[:, col] < xmin
                above = X[:, col] > xmax
                if np.any(below):
                    ref = self._bspline_basis(np.array([xmin]), self.knots_[col], self.degree)
                    if not self.include_bias and ref.shape[1] > 1:
                        ref = ref[:, 1:]
                    basis[below] = ref[0]
                if np.any(above):
                    ref = self._bspline_basis(np.array([xmax - 1e-10]), self.knots_[col], self.degree)
                    if not self.include_bias and ref.shape[1] > 1:
                        ref = ref[:, 1:]
                    basis[above] = ref[0]
            parts.append(basis)
        return np.hstack(parts)


# ---------------------------------------------------------------------------
# TargetEncoder
# ---------------------------------------------------------------------------

class TargetEncoder(BaseEstimator, TransformerMixin):
    """Encode categorical features using target mean with cross-fitting."""

    def __init__(self, *, categories='auto', target_type='auto',
                 smooth='auto', cv=5, shuffle=True, random_state=None):
        self.categories = categories
        self.target_type = target_type
        self.smooth = smooth
        self.cv = cv
        self.shuffle = shuffle
        self.random_state = random_state
        self.categories_ = None
        self.encodings_ = None
        self.target_mean_ = None

    def fit(self, X, y):
        X = np.asarray(X)
        y = np.asarray(y, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n_features = X.shape[1]
        self.target_mean_ = y.mean()
        self.categories_ = []
        self.encodings_ = []
        smooth = self.smooth
        if smooth == 'auto':
            smooth = max(1.0, y.var())
        for col in range(n_features):
            cats = np.unique(X[:, col])
            self.categories_.append(cats)
            encoding = {}
            for cat in cats:
                mask = X[:, col] == cat
                n_cat = mask.sum()
                cat_mean = y[mask].mean()
                # Shrinkage toward global mean
                weight = n_cat / (n_cat + smooth)
                encoding[cat] = weight * cat_mean + (1 - weight) * self.target_mean_
            self.encodings_.append(encoding)
        return self

    def transform(self, X):
        X = np.asarray(X)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n_samples, n_features = X.shape
        result = np.full((n_samples, n_features), self.target_mean_, dtype=float)
        for col in range(n_features):
            encoding = self.encodings_[col]
            for i in range(n_samples):
                val = X[i, col]
                if val in encoding:
                    result[i, col] = encoding[val]
        return result

    def fit_transform(self, X, y):
        X = np.asarray(X)
        y = np.asarray(y, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n_samples, n_features = X.shape
        self.target_mean_ = y.mean()
        smooth = self.smooth
        if smooth == 'auto':
            smooth = max(1.0, y.var())
        # Fit global encodings
        self.fit(X, y)
        # Cross-validated encoding for training data
        rng = np.random.RandomState(self.random_state)
        indices = np.arange(n_samples)
        if self.shuffle:
            rng.shuffle(indices)
        folds = np.array_split(indices, self.cv)
        result = np.full((n_samples, n_features), self.target_mean_, dtype=float)
        for fold_idx in range(self.cv):
            val_idx = folds[fold_idx]
            train_idx = np.concatenate([folds[j] for j in range(self.cv) if j != fold_idx])
            X_train, y_train = X[train_idx], y[train_idx]
            for col in range(n_features):
                cats = self.categories_[col]
                for cat in cats:
                    mask_train = X_train[:, col] == cat
                    n_cat = mask_train.sum()
                    if n_cat > 0:
                        cat_mean = y_train[mask_train].mean()
                        weight = n_cat / (n_cat + smooth)
                        enc_val = weight * cat_mean + (1 - weight) * self.target_mean_
                    else:
                        enc_val = self.target_mean_
                    mask_val = X[val_idx, col] == cat
                    result[val_idx[mask_val], col] = enc_val
        return result
